const f = msg.payload || {};
let header = 'Everything is OK';
let detail = '';
let color = '#4caf50';
if (f.fault && f.fault !== 'ok') {
    header = f.fault.replace(/_/g, ' ').toUpperCase();
    detail = (f.recommended_first_check || '') + (f.safety_note ? '\n\n[SAFETY] ' + f.safety_note : '');
    color = f.confidence >= 0.85 ? '#f44336' : '#ff9800';
}
msg.payload = `**${header}**\n\n${detail}`;
msg.ui_update = {color};
return msg;

msg.url = 'http://fault-sim:8089/inject/' + msg.payload;
msg.method = 'POST';
msg.payload = {};
return msg;

const rows = (msg.payload || []).map(r => ({
  When: r.ts,
  Fault: (r.fault || '').replace(/_/g, ' '),
  Conf: r.confidence,
  Affected: (JSON.parse(r.affected_json || '[]') || []).join(', '),
}));
msg.payload = rows;
return msg;

// For the booth demo, call Groq directly. The full Supervisor at
// mira-pipeline:9099 owns intent + safety + FSM and is tuned for real
// technician chat — it short-circuits if the embedded fault context
// trips safety keywords, which makes booth demos messy. Production
// chat should still route through the Supervisor.
const fault = flow.get('current_fault') || {fault: 'ok'};
const question = msg.payload || '';
const evidence = (fault.evidence || []).map(e => `- ${e.topic}: ${JSON.stringify(e.value)}${e.note ? ' (' + e.note + ')' : ''}`).join('\n');
const affected = (fault.affected_components || []).join(', ');
const lower = question.toLowerCase();
if (/(^|\s)(yes|confirm|correct|ok|yep|yeah|y)(\s|$|[.!])/.test(lower)) {
    flow.set('confirmed_session', true);
}
const confirmedNow = flow.get('confirmed_session') || false;
const sys = [
    'You are MIRA — a calm, evidence-based maintenance supervisor.',
    'You answer briefly. You cite evidence. You never invent plant data.',
    '',
    'LIVE CONVEYOR STATE (Demo Cell / Conveyor CV-101):',
    '  active fault: ' + (fault.fault || 'ok'),
    '  confidence: ' + (fault.confidence || 0),
    '  affected components: ' + (affected || 'none'),
    '  evidence:',
    (evidence || '  (no evidence yet)'),
    '  recommended first check (raw): ' + (fault.recommended_first_check || 'n/a'),
    '  safety note (raw): ' + (fault.safety_note || 'standard plant PPE'),
    '',
    confirmedNow
        ? 'The technician has CONFIRMED the location. Reply directly with: diagnosis, confidence, evidence (bulleted), recommended first check, next measurement, safety note, work-order draft (one line). Under 180 words.'
        : 'MIRA protocol — first reply must be EXACTLY: "I believe you are working on Demo Cell / Conveyor CV-101 / ' + (affected || 'the suspected fault area') + '. Confirm?" — then stop. Do not diagnose until the technician says yes.',
].join('\n');
msg.url = 'https://api.groq.com/openai/v1/chat/completions';
msg.method = 'POST';
msg.headers = {
    'Content-Type': 'application/json',
    'Authorization': 'Bearer ' + env.get('GROQ_API_KEY'),
};
msg.payload = {
    model: 'llama-3.3-70b-versatile',
    messages: [
        {role: 'system', content: sys},
        {role: 'user', content: question},
    ],
    stream: false,
    temperature: 0.2,
    max_tokens: 400,
};
return msg;

let txt = '(no reply)';
try {
    if (msg.statusCode === 200 && msg.payload && msg.payload.choices && msg.payload.choices.length) {
        txt = msg.payload.choices[0].message.content || txt;
    } else if (msg.statusCode) {
        txt = '(MIRA pipeline returned ' + msg.statusCode + ')';
    }
} catch (e) { txt = '(parse error: ' + e.message + ')'; }
msg.payload = txt;
return msg;

// Stream B (Node-RED Modbus, failover) — emit one read spec per MAPPED block.
// The Micro 820 (Conv_Simple_1.5) rejects any read spanning an unmapped
// address, so we read only the contiguous mapped blocks. Block identity is
// recovered downstream from msg.modbusRequest (set by the flex-getter).
const blocks = [
  {fc:1, address:0,   quantity:1},
  {fc:1, address:3,   quantity:1},
  {fc:1, address:5,   quantity:1},
  {fc:1, address:9,   quantity:1},
  {fc:1, address:11,  quantity:9},
  {fc:3, address:106, quantity:4},
  {fc:3, address:114, quantity:1},
];
return [blocks.map(b => ({payload: {value: null, unitid: 1, fc: b.fc, address: b.address, quantity: b.quantity}}))];

// Stream B publish — identify the returned block via msg.modbusRequest, map
// values onto the live 18-point Conv_Simple_1.5 map, publish source-qualified
// _streams/nr/* (source:"plc-nr"). HR scaling per MIRA_PLC PLC_MODBUS_TCP.md.
const req = msg.modbusRequest || {};
const vals = msg.payload;
if (!Array.isArray(vals)) return null;
const PFX = 'demo/cell1/conveyor/cv101/_streams/nr/';
const COIL = {0:'motor/m101/running',3:'vfd/vfd101/comm_ok',5:'safety/estop',9:'safety/wiring',
  11:'plc/di/di00_fwd',12:'plc/di/di01_rev',13:'plc/di/di02_estop_nc',14:'plc/di/di03_estop_no',
  15:'plc/di/di04_pbrun',16:'plc/do/do00_green',17:'plc/do/do01_red',18:'safety/contactor_q1',
  19:'plc/do/do03_pbrun_led'};
const HR = {106:['vfd/vfd101/freq',100],107:['vfd/vfd101/current_a',100],108:['vfd/vfd101/voltage_v',10],
  109:['vfd/vfd101/dc_bus_v',10],114:['vfd/vfd101/cmd_word',1]};
const ts = Date.now()/1000;
const env = (v) => JSON.stringify({value: v, ts: ts, source: 'plc-nr'});
const base = parseInt(req.address);
const fc = parseInt(req.fc);
const out = [];
for (let i = 0; i < vals.length; i++) {
  const off = base + i;
  if (fc === 1 && COIL[off] !== undefined) {
    out.push({topic: PFX + COIL[off], payload: env(!!vals[i])});
  } else if (fc === 3 && HR[off] !== undefined) {
    const spec = HR[off];
    out.push({topic: PFX + spec[0], payload: env(spec[1] === 1 ? vals[i] : vals[i] / spec[1])});
  }
}
// liveness marker emitted with the first coil block
if (fc === 1 && base === 0) out.push({topic: PFX + 'plc/link', payload: env(true)});
if (out.length === 0) return null;
return [out];

