// Stream router: forward ONLY the active PLC stream to the bare panel topics
// the live PLC I/O widgets subscribe to. Inactive stream is dropped. Active is
// the selector choice (flow 'streamMode'), or auto-failover (prefer the Python
// bridge, fall to Node-RED when the bridge goes stale).
const FRESH_MS = 2500;
const now = Date.now();
const m = (msg.topic || '').match(/\/_streams\/(bridge|nr)\/(.+)$/);
if (!m) return null;
const stream = m[1], rel = m[2];
const seen = flow.get('streamSeen') || {};
seen[stream] = now;
flow.set('streamSeen', seen);
const mode = flow.get('streamMode') || 'auto';
const fresh = (s) => seen[s] && (now - seen[s]) < FRESH_MS;
let active;
if (mode === 'bridge' || mode === 'nr') active = mode;
else active = fresh('bridge') ? 'bridge' : (fresh('nr') ? 'nr' : null);
flow.set('streamActive', active);
if (stream !== active) return null;
msg.topic = 'demo/cell1/conveyor/cv101/' + rel;
return msg;

// Selector -> active-stream mode (auto | bridge | nr)
flow.set('streamMode', msg.payload);
return null;

// Watchdog: recompute per-stream health + active label every tick so a dead
// stream's LED flips even when no messages arrive.
const FRESH_MS = 2500;
const now = Date.now();
const seen = flow.get('streamSeen') || {};
const fresh = (s) => seen[s] && (now - seen[s]) < FRESH_MS;
const active = flow.get('streamActive');
const led = (s) => {
  const ok = fresh(s);
  return {payload: ok ? '\u25CF live' : '\u25CB down', ui_update: {color: ok ? '#66bb6a' : '#ef5350'}};
};
const names = {bridge: 'Python bridge', nr: 'Node-RED Modbus'};
const activeTxt = {
  payload: active ? ('\u25B6 ' + (names[active] || active)) : '\u2014 no live PLC \u2014',
  ui_update: {color: active ? '#90caf9' : '#ffa726'}
};
return [activeTxt, led('bridge'), led('nr')];

const rel = (msg.topic||'').replace('demo/cell1/conveyor/cv101/','');
